mapper.insert:
insert into public_agent_config_rollouts(
    rollout_id, branch, commit_hash, status, trace_id, created_at, updated_at
) values (#{rolloutId}, #{branch}, #{commitHash}, 'DRAINING', #{traceId}, #{now}, #{now})

insert into public_agent_config_rollout_targets(
    target_id, rollout_id, linux_server_id, container_id, port, base_url,
    status, retry_count, next_retry_at, lease_until, created_at, updated_at
) values (
    #{row.targetId}, #{row.rolloutId}, #{row.linuxServerId}, #{row.containerId}, #{row.port}, #{row.baseUrl},
    'RETRY_WAIT', #{row.retryCount}, #{now}, null, #{now}, #{now}
) on conflict (rollout_id, linux_server_id, container_id, port) do nothing

mapper.update:
update public_agent_config_rollout_servers
set status = 'SYNCED', synced_at = #{now}, updated_at = #{now}
where rollout_id = #{rolloutId} and linux_server_id = #{linuxServerId}

update public_agent_config_rollout_targets
set status = 'PROCESSING', lease_until = #{leaseUntil}, updated_at = #{now}
where target_id = #{targetId}

update public_agent_config_rollout_targets
set status = 'RETRY_WAIT', retry_count = #{retryCount}, next_retry_at = #{nextRetryAt},
    lease_until = null, last_error = #{errorMessage}, updated_at = #{now}
where target_id = #{targetId}

update public_agent_config_rollout_targets
set status = 'DISPOSED', disposed_at = #{now}, lease_until = null, last_error = null, updated_at = #{now}
where target_id = #{targetId}

update public_agent_config_rollouts
set status = 'FAILED', failure_reason = #{reason}, completed_at = #{now}, updated_at = #{now}
where rollout_id = #{rolloutId} and status = 'DRAINING'
